```java
public class Main {
    public static void main(String[] args) {
        // Объявление массива целых чисел
        int[] array = {1, 2, 3, 4, 5};

        // Печать исходного массива
        System.out.println("Исходный массив: ");
        for (int i = 0; i < array.length; i++) {
            System.out.print(array[i] + " ");
        }
        System.out.println();

        // Манипулирование массивом
        // 1. Добавление элемента в конец массива
        int[] newArray = new int[array.length + 1];
        System.arraycopy(array, 0, newArray, 0, array.length);
        newArray[newArray.length - 1] = 6;
        array = newArray;

        // 2. Удаление элемента из массива
        int[] newArray2 = new int[array.length - 1];
        System.arraycopy(array, 0, newArray2, 0, array.length - 1);
        array = newArray2;

        // 3. Замена элемента в массиве
        array[1] = 10;

        // 4. Сортировка массива
        for (int i = 0; i < array.length; i++) {
            for (int j = i + 1; j < array.length; j++) {
                if (array[i] > array[j]) {
                    int temp = array[i];
                    array[i] = array[j];
                    array[j] = temp;
                }
            }
        }

        // Печать манипулированного массива
        System.out.println("Манипулированный массив: ");
        for (int i = 0; i < array.length; i++) {
            System.out.print(array[i] + " ");
        }
        System.out.println();
    }
}
```

