    public static void main(String[] args) {
        String kalimat = "Nggaue program sing bis a digunakake kanggo ngudit basis data perintah sing sentitif";
        int jumlahNggaue = hitungNggaue(kalimat);
        System.out.println("Jumlah perintah 'nggaue' dalam kalimat: " + jumlahNggaue);
